/// <summary>
/// This class is an extension of form EcoResProductDetailsExtended, dataSources Sales, field ETGDepositNeeded.
/// </summary>
[ExtensionOf(formDataFieldStr(EcoResProductDetailsExtended, Sales, ETGDepositNeeded))]
internal final class ETGEcoResProductDetailsExtended_Sales_Extension
{
}

Method.Source:
/// <summary>
/// When ETGDepositNeeded field is modified PackSize field will be editable when it is set as Yes.
/// </summary>
public void modified()
{
    next modified();

    if(SalesParameters::find().ETGEnableCylinderTracking)
    {
        FormDataObject    formDataObject    = any2Object(this) as FormDataObject;
        FormDataSource    formDataSource    = formDataObject.datasource();
        InventTableModule inventTableModule = formDataSource.cursor();

        formDataSource.object(fieldNum(InventTableModule, ETGPackSize)).allowEdit(inventTableModule.ETGDepositNeeded == NoYes::Yes);
    }

}
